INSERT INTO examples (name, category, framework, files, dependencies, metadata) VALUES ('"clearfix"', '"Prsnt"', '"vanilla"', '{"demo.css": ".clearfix::after {\n  content: '''';\n  display: block;\n  clear: both;\n}\n\n.floated {\n  float: left;\n  padding: 4px;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Clearfix\r\n    </h1>\r\n    <div class=\"clearfix\">\r\n      <div class=\"floated\">float a</div>\r\n      <div class=\"floated\">float b</div>\r\n      <div class=\"floated\">float c</div>\r\n    </div>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/clearfix"}'), ('"constant-width-to-height-ratio"', '"Prsnt"', '"vanilla"', '{"demo.css": ".constant-width-to-height-ratio {\n  background: #9C27B0;\n  width: 50%;\n}\n\n.constant-width-to-height-ratio::before {\n  content: '''';\n  padding-top: 100%;\n  float: left;\n}\n\n.constant-width-to-height-ratio::after {\n  content: '''';\n  display: block;\n  clear: both;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Constant width to height ratio\r\n    </h1>\r\n    <div class=\"constant-width-to-height-ratio\"></div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/constant-width-to-height-ratio"}'), ('"display-table-centering"', '"Prsnt"', '"vanilla"', '{"demo.css": ".container {\n  border: 1px solid #9C27B0;\n  height: 250px;\n  width: 250px;\n}\n\n.center {\n  display: table;\n  height: 100%;\n  width: 100%;\n}\n\n.center > span {\n  display: table-cell;\n  text-align: center;\n  vertical-align: middle;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Display table centering\r\n    </h1>\r\n    <div class=\"container\">\r\n      <div class=\"center\"><span>Centered content</span></div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/display-table-centering"}'), ('"evenly-distributed-children"', '"Prsnt"', '"vanilla"', '{"demo.css": ".evenly-distributed-children {\n  display: flex;\n  justify-content: space-between;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Evenly distributed children\r\n    </h1>\r\n    <div class=\"evenly-distributed-children\">\r\n      <p>Item1</p>\r\n      <p>Item2</p>\r\n      <p>Item3</p>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/evenly-distributed-children"}'), ('"fit-image-in-container"', '"Prsnt"', '"vanilla"', '{"demo.css": ".image {\n  background: #34495e;\n  border: 1px solid #34495e;\n  width: 200px;\n  height: 200px;\n}\n\n.image-contain {\n  object-fit: contain;\n  object-position: center;\n}\n\n.image-cover {\n  object-fit: cover;\n  object-position: right top;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Fit image in container\r\n    </h1>\r\n    <img class=\"image image-contain\" src=\"https://picsum.photos/600/200\" />\r\n    <img class=\"image image-cover\" src=\"https://picsum.photos/600/200\" />\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/fit-image-in-container"}'), ('"flexbox-centering"', '"Prsnt"', '"vanilla"', '{"demo.css": ".flexbox-centering {\n  display: flex;\n  justify-content: center;\n  align-items: center;\n  height: 100px;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Flexbox centering\r\n    </h1>\r\n    <div class=\"flexbox-centering\">\r\n      <div>Centered content.</div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/flexbox-centering"}'), ('"full-width-image"', '"Prsnt"', '"vanilla"', '{"demo.css": "main {\n  margin: 0 auto;\n  max-width: 640px;\n}\n\nimg {\n  height: auto;\n  max-width: 100%;\n}\n\n.full-width {\n  position: relative;\n  left: 50%;\n  right: 50%;\n  margin-left: -50vw;\n  margin-right: -50vw;\n  max-width: 100vw;\n  width: 100vw;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Static Template\r\n    </h1>\r\n    <main>\r\n      <h4>Lorem ipsum dolor sit amet</h4>\r\n      <p>\r\n        Lorem ipsum dolor sit amet, consectetur adipiscing elit. Mauris molestie\r\n        lobortis sapien, sit amet iaculis est interdum tincidunt. Nunc egestas\r\n        nibh ut metus elementum consequat. Integer elit orci, rhoncus efficitur\r\n        lectus eu, faucibus interdum felis.\r\n      </p>\r\n      <p>\r\n        <img\r\n          class=\"full-width\"\r\n          src=\"https://picsum.photos/id/257/2560/1440.jpg\"\r\n        />\r\n      </p>\r\n      <p>\r\n        Orci varius natoque penatibus et magnis dis parturient montes, nascetur\r\n        ridiculus mus. Nullam pretium lectus sed ex efficitur, ac varius sapien\r\n        gravida. Sed facilisis elit quis sem sollicitudin, ut aliquam neque\r\n        eleifend. Maecenas sagittis neque sapien, ac tempus nulla tempus nec.\r\n        Curabitur tellus est, convallis id dolor ut, porta hendrerit quam.\r\n      </p>\r\n    </main>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/full-width-image"}'), ('"grid-centering"', '"Prsnt"', '"vanilla"', '{"demo.css": ".grid-centering {\n  display: grid;\n  justify-content: center;\n  align-items: center;\n  height: 100px;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Grid centering\r\n    </h1>\r\n    <div class=\"grid-centering\">\r\n      <div class=\"child\">Centered content.</div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/grid-centering"}'), ('"holy-grail"', '"Prsnt"', '"vanilla"', '{"demo.css": ".holy-grail {\n  display: flex;\n  flex-direction: column;\n}\n\n.holy-grail__main {\n  /* Take the remaining height */\n  flex-grow: 1;\n\n  /* Layout the left sidebar, main content and right sidebar */\n  display: flex;\n  flex-direction: row;\n}\n\n.holy-grail__left {\n  width: 25%;\n}\n\n.holy-grail__middle {\n  /* Take the remaining width */\n  flex-grow: 1;\n}\n\n.holy-grail__right {\n  width: 20%;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Holy Grail\r\n    </h1>\r\n    <div class=\"holy-grail\">\r\n      <header>Header</header>\r\n      <main class=\"holy-grail__main\">\r\n        <!-- Left sidebar -->\r\n        <aside class=\"holy-grail__left\">Left</aside>\r\n\r\n        <!-- Main content -->\r\n        <article class=\"holy-grail__middle\">Middle</article>\r\n\r\n        <!-- Right sidebar -->\r\n        <nav class=\"holy-grail__right\">Right</nav>\r\n      </main>\r\n      <footer>Footer</footer>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/holy-grail"}'), ('"how-can-i-ensure-the-footer-is-always-at-the-bottom-of-the-page"', '"Prsnt"', '"vanilla"', '{"demo.css": "/* flexbox */\nbody {\n  min-height: 100vh;\n  display: flex;\n  flex-direction: column;\n}\n\nfooter {\n  margin-top: auto;\n}\n\n/* grid */\nbody {\n  min-height: 100vh;\n  display: grid;\n  grid-template-rows: 1fr auto;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      How can I ensure the footer is always at the bottom of the page?\r\n    </h1>\r\n    <div style=\"margin: 1rem;\">\r\n      Preventing the footer from floating up the page is important when trying\r\n      to create a polished website. Pages with\r\n      <strong>short content</strong> can run into this issue, but it''s easy to\r\n      fix with a few lines of CSS. Assuming your HTML looks something like the\r\n      snippet below, here are two modern ways to ensure the footer is always at\r\n      the bottom of the page:\r\n    </div>\r\n    <main>Main</main>\r\n    <footer>Footer</footer>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/how-can-i-ensure-the-footer-is-always-at-the-bottom-of-the-page"}'), ('"masonary-grid"', '"Prsnt"', '"vanilla"', '{"demo.css": ".masonry-grid {\n  /* It is split into 3 columns */\n  column-count: 3;\n\n  /* The space between columns */\n  column-gap: 1rem;\n}\n\n.masonry-grid__item {\n  /* Prevent a column from breaking into multiple columns */\n  break-inside: avoid;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Masonary Grid\r\n    </h1>\r\n    <div class=\"masonry-grid\">\r\n      <!--Item -->\r\n      Item\r\n      <div class=\"masonry-grid__item\">...</div>\r\n\r\n      <!-- Repeat other items -->\r\n      Repeat other items\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/masonary-grid"}'), ('"masonry-layout"', '"Prsnt"', '"vanilla"', '{"demo.css": "/* Container */\n.masonry-container {\n  --column-count-small: 1;\n  --column-count-medium: 2;\n  --column-count-large: 3;\n  --column-gap: 0.125rem;\n  padding: var(--column-gap);\n}\n\n/* Columns */\n.masonry-columns {\n  column-gap: var(--column-gap);\n  column-count: var(--column-count-small);\n  column-width: calc(1 / var(--column-count-small) * 100%);\n}\n\n@media only screen and (min-width: 640px) {\n  .masonry-columns {\n    column-count: var(--column-count-medium);\n    column-width: calc(1 / var(--column-count-medium) * 100%);\n  }\n}\n\n@media only screen and (min-width: 800px) {\n  .masonry-columns {\n    column-count: var(--column-count-large);\n    column-width: calc(1 / var(--column-count-large) * 100%);\n  }\n}\n\n/* Bricks */\n.masonry-brick {\n  width: 100%;\n  height: auto;\n  margin: var(--column-gap) 0;\n  display: block;\n}\n\n.masonry-brick:first-child {\n  margin: 0 0 var(--column-gap);\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Masonry Layout\r\n    </h1>\r\n    <div class=\"masonry-container\">\r\n      <div class=\"masonry-columns\">\r\n        <img\r\n          class=\"masonry-brick\"\r\n          src=\"https://picsum.photos/id/1016/384/256\"\r\n          alt=\"An image\"\r\n        />\r\n        <img\r\n          class=\"masonry-brick\"\r\n          src=\"https://picsum.photos/id/1025/495/330\"\r\n          alt=\"Another image\"\r\n        />\r\n        <img\r\n          class=\"masonry-brick\"\r\n          src=\"https://picsum.photos/id/1024/192/128\"\r\n          alt=\"Another image\"\r\n        />\r\n        <img\r\n          class=\"masonry-brick\"\r\n          src=\"https://picsum.photos/id/1028/518/345\"\r\n          alt=\"One more image\"\r\n        />\r\n        <img\r\n          class=\"masonry-brick\"\r\n          src=\"https://picsum.photos/id/1035/585/390\"\r\n          alt=\"And another one\"\r\n        />\r\n        <img\r\n          class=\"masonry-brick\"\r\n          src=\"https://picsum.photos/id/1074/384/216\"\r\n          alt=\"Last one\"\r\n        />\r\n      </div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/masonry-layout"}'), ('"menu-on-image-hover"', '"Prsnt"', '"vanilla"', '{"demo.css": ".hover-menu {\n  position: relative;\n  overflow: hidden;\n  margin: 8px;\n  min-width: 340px;\n  max-width: 480px;\n  max-height: 290px;\n  width: 100%;\n  background: #000;\n  text-align: center;\n  box-sizing: border-box;\n}\n\n.hover-menu * {\n  box-sizing: border-box;\n}\n\n.hover-menu img {\n  position: relative;\n  max-width: 100%;\n  top: 0;\n  right: 0;\n  opacity: 1;\n  transition: 0.3s ease-in-out;\n}\n\n.hover-menu div {\n  position: absolute;\n  top: 0;\n  left: -120px;\n  width: 120px;\n  height: 100%;\n  padding: 8px 4px;\n  background: #000;\n  transition: 0.3s ease-in-out;\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n}\n\n.hover-menu div a {\n  display: block;\n  line-height: 2;\n  color: #fff;\n  text-decoration: none;\n  opacity: 0.8;\n  padding: 5px 15px;\n  position: relative;\n  transition: 0.3s ease-in-out;\n}\n\n.hover-menu div a:hover {\n  text-decoration: underline;\n}\n\n.hover-menu:hover img {\n  opacity: 0.5;\n  right: -120px;\n}\n\n.hover-menu:hover div {\n  left: 0;\n  opacity: 1;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Menu on image hover\r\n    </h1>\r\n    <figure class=\"hover-menu\">\r\n      <img src=\"https://picsum.photos/id/1060/800/480.jpg\" />\r\n      <div>\r\n        <a href=\"#\">Home</a>\r\n        <a href=\"#\">Pricing</a>\r\n        <a href=\"#\">About</a>\r\n      </div>\r\n    </figure>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/menu-on-image-hover"}'), ('"offscreen"', '"Prsnt"', '"vanilla"', '{"demo.css": ".offscreen {\n  border: 0;\n  clip: rect(0 0 0 0);\n  height: 1px;\n  margin: -1px;\n  overflow: hidden;\n  padding: 0;\n  position: absolute;\n  width: 1px;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Offscreen\r\n    </h1>\r\n    <a class=\"button\" href=\"https://google.com\">\r\n      Learn More <span class=\"offscreen\"> about pants</span>\r\n    </a>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/offscreen"}'), ('"responsive-image-mosaic"', '"Prsnt"', '"vanilla"', '{"demo.css": ".image-mosaic {\n  display: grid;\n  gap: 1rem;\n  grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));\n  grid-auto-rows: 240px;\n}\n\n.card {\n  display: flex;\n  flex-direction: column;\n  justify-content: center;\n  align-items: center;\n  background: #353535;\n  font-size: 3rem;\n  color: #fff;\n  box-shadow: rgba(3, 8, 20, 0.1) 0px 0.15rem 0.5rem, rgba(2, 8, 20, 0.1) 0px 0.075rem 0.175rem;\n  height: 100%;\n  width: 100%;\n  border-radius: 4px;\n  transition: all 500ms;\n  overflow: hidden;\n  background-size: cover;\n  background-position: center;\n  background-repeat: no-repeat;\n  padding: 0;\n  margin: 0;\n}\n\n@media screen and (min-width: 600px) {\n  .card-tall {\n    grid-row: span 2 / auto;\n  }\n\n  .card-wide {\n    grid-column: span 2 / auto;\n  }\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Responsive image mosaic\r\n    </h1>\r\n    <div class=\"image-mosaic\">\r\n      <div\r\n        class=\"card card-tall card-wide\"\r\n        style=\"background-image: url(''https://picsum.photos/id/564/1200/800'');\"\r\n      ></div>\r\n      <div\r\n        class=\"card card-tall\"\r\n        style=\"background-image: url(''https://picsum.photos/id/566/800/530'');\"\r\n      ></div>\r\n      <div\r\n        class=\"card\"\r\n        style=\"background-image: url(''https://picsum.photos/id/575/800/530'');\"\r\n      ></div>\r\n      <div\r\n        class=\"card\"\r\n        style=\"background-image: url(''https://picsum.photos/id/626/800/530'');\"\r\n      ></div>\r\n      <div\r\n        class=\"card\"\r\n        style=\"background-image: url(''https://picsum.photos/id/667/800/530'');\"\r\n      ></div>\r\n      <div\r\n        class=\"card\"\r\n        style=\"background-image: url(''https://picsum.photos/id/678/800/530'');\"\r\n      ></div>\r\n      <div\r\n        class=\"card card-wide\"\r\n        style=\"background-image: url(''https://picsum.photos/id/695/800/530'');\"\r\n      ></div>\r\n      <div\r\n        class=\"card\"\r\n        style=\"background-image: url(''https://picsum.photos/id/683/800/530'');\"\r\n      ></div>\r\n      <div\r\n        class=\"card\"\r\n        style=\"background-image: url(''https://picsum.photos/id/693/800/530'');\"\r\n      ></div>\r\n      <div\r\n        class=\"card\"\r\n        style=\"background-image: url(''https://picsum.photos/id/715/800/530'');\"\r\n      ></div>\r\n      <div\r\n        class=\"card\"\r\n        style=\"background-image: url(''https://picsum.photos/id/610/800/530'');\"\r\n      ></div>\r\n      <div\r\n        class=\"card\"\r\n        style=\"background-image: url(''https://picsum.photos/id/599/800/530'');\"\r\n      ></div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/responsive-image-mosaic"}'), ('"responsive-layout-with-sidebar"', '"Prsnt"', '"vanilla"', '{"demo.css": ".container {\n  display: grid;\n  grid-template-columns: 1fr minmax(150px, 20%);\n  height: 100px;\n}\n\nmain,\naside {\n  padding: 12px;\n  text-align: center;\n}\n\nmain {\n  background: #d4f2c4;\n}\n\naside {\n  background: #81cfd9;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Responsive layout with sidebar\r\n    </h1>\r\n    <div class=\"container\">\r\n      <main>\r\n        This element is 1fr large.\r\n      </main>\r\n      <aside>\r\n        Min: 150px / Max: 20%\r\n      </aside>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/responsive-layout-with-sidebar"}'), ('"root-versus-html"', '"Prsnt"', '"vanilla"', '{"demo.css": ":root {\n  background-color: red;\n}\n\nhtml {\n  background-color: blue;\n}\n\n/* The HTML document''s root element will have a red background-color.  */\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      What''s the difference between :root and html in CSS?\r\n    </h1>\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/root-versus-html"}'), ('"same-height-columns"', '"Prsnt"', '"vanilla"', '{"Same_height_columns.html": "<div class=\"same-height-columns\">\n  <!-- Column -->\n  <div class=\"same-height-columns__column\">\n    <!-- Cover -->\n    ...\n\n    <!-- Content -->\n    <div class=\"same-height-columns__content\">...</div>\n\n    <!-- Button sticks to the bottom -->\n    ...\n  </div>\n\n  <!-- Repeat with other columns -->\n  ...\n</div>\n", "demo.css": ".same-height-columns {\n  display: flex;\n}\n\n.same-height-columns__column {\n  flex: 1;\n  /* Space between columns */\n  margin: 0 8px;\n\n  /* Layout each column */\n  display: flex;\n  flex-direction: column;\n}\n\n.same-height-columns__content {\n  /* Take available height */\n  flex: 1;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Same Height Columns\r\n    </h1>\r\n    <div class=\"same-height-columns\">\r\n      <!-- Column -->\r\n      <div class=\"same-height-columns__column\">\r\n        <!-- Cover -->\r\n        Cover\r\n\r\n        <!-- Content -->\r\n        <div class=\"same-height-columns__content\">Content</div>\r\n\r\n        <!-- Button sticks to the bottom -->\r\n        Button here\r\n      </div>\r\n\r\n      <!-- Repeat with other columns -->\r\n      Repeat with other columns\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/same-height-columns"}'), ('"sidebar"', '"Prsnt"', '"vanilla"', '{"demo.css": ".sidebar {\n  display: flex;\n}\n\n.sidebar__sidebar {\n  width: 30%;\n}\n\n.sidebar__main {\n  /* Take the remaining width */\n  flex: 1;\n\n  /* Make it scrollable */\n  overflow: auto;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Sidebar\r\n    </h1>\r\n    <div class=\"sidebar\">\r\n      <!-- Sidebar -->\r\n      <aside class=\"sidebar__sidebar\">Aside</aside>\r\n\r\n      <!-- Main -->\r\n      <main class=\"sidebar__main\">Main</main>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/sidebar"}'), ('"simple-grid"', '"Prsnt"', '"vanilla"', '{"demo.css": ".simple-grid {\n  display: flex;\n\n  margin-left: -0.25rem;\n  margin-right: -0.25rem;\n}\n\n.simple-grid__cell {\n  padding-left: 0.25rem;\n  padding-right: 0.25rem;\n}\n\n.simple-grid__cell--fill {\n  flex: 1;\n}\n\n/* Cell with given width */\n.simple-grid__cell--1\\/2 {\n  flex: 0 0 50%;\n}\n.simple-grid__cell--1\\/3 {\n  flex: 0 0 33.3333333%;\n}\n.simple-grid__cell--1\\/4 {\n  flex: 0 0 25%;\n}\n", "demo.html": "<!DOCTYPE html>\r\n<html lang=\"en\">\r\n  <head>\r\n    <meta charset=\"UTF-8\" />\r\n    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\" />\r\n    <meta http-equiv=\"X-UA-Compatible\" content=\"ie=edge\" />\r\n    <link rel=\"stylesheet\" href=\"style.css\" />\r\n    <title>Static Template</title>\r\n  </head>\r\n  <body>\r\n    <h1>\r\n      Simple Grid\r\n    </h1>\r\n    <!-- Row -->\r\n    <div class=\"simple-grid\">\r\n      <!--Cell with given width. Replace 25% with whatever you want -->\r\n      <div class=\"simple-grid__cell simple-grid__cell--1/4\">25%</div>\r\n\r\n      <!-- Cell that takes remaining width -->\r\n      <div class=\"simple-grid__cell simple-grid__cell--fill\">...</div>\r\n    </div>\r\n\r\n    <script src=\"script.js\"></script>\r\n  </body>\r\n</html>\r\n"}', '{}', '{"original_path": "Vanilla/Prsnt/Layout/simple-grid"}');